func tokenUsageJSON(stats *types.TokenUsageStats) string {
	b, _ := sonic.Marshal(stats)
	return string(b)
}

func buildTokenUsageURL(activeRange, groupBy, since, until string) string {
	q := url.Values{}
	q.Set("groupBy", groupBy)
	if since != "" && until != "" {
		q.Set("since", since)
		q.Set("until", until)
	} else {
		if activeRange == "" {
			activeRange = "7d"
		}
		q.Set("range", activeRange)
	}
	return "/service/web/home/token-usage?" + q.Encode()
}

func tokenUsageRangeBtnClass(activeRange, preset string) string {
	if activeRange == preset {
		return "join-item btn btn-sm btn-active"
	}
	return "join-item btn btn-sm"
}

func formatTokenCount(n int64) string {
	switch {
	case n >= 1_000_000_000:
		return fmt.Sprintf("%.1fB", float64(n)/1_000_000_000)
	case n >= 1_000_000:
		return fmt.Sprintf("%.1fM", float64(n)/1_000_000)
	case n >= 1_000:
		return fmt.Sprintf("%.1fK", float64(n)/1_000)
	default:
		return fmt.Sprint(n)
	}
}

